const encryptedCode = ``;

function run() {
  const input = prompt("Anna salasana");

  // generate password variations
  const attempts = [
    input,
    input.trim(),
    input.replace(/\s+/g, ""),
    input.toLowerCase(),
    input.toUpperCase(),
    input.trim().toLowerCase(),
    input.trim().toUpperCase()
  ];

  for (let password of attempts) {
    try {
      const bytes = CryptoJS.AES.decrypt(encryptedCode, password);

      // try both decoding methods
      const decrypted1 = bytes.toString(CryptoJS.enc.Utf8);
      const decrypted2 = CryptoJS.enc.Utf8.stringify(bytes);

      const decrypted = decrypted1 || decrypted2;

      if (decrypted && decrypted.length > 0) {
        new Function(decrypted)();
        return;
      }

    } catch (e) {}
  }

  alert("Väärä salasana tai tuli virhe");
}

run();
